## `pcapng_stubs.cpp` – C‑stub (compiled as C++)

```cpp
/*--------------------------------------------------------------------
   pcapng_stubs.cpp

   OCaml <-> C++ glue for libpcapng.
   Build with something like:
     ocamlc -c -custom -ccopt -std=c++17 pcapng_stubs.cpp
   and link with -lpcapng (or whatever library provides the iterator).

   The code deliberately avoids any heavy libpcapng internals – it
   only shows the pattern needed to expose a C++ iterator as an OCaml
   callback.  Replace the mock‑up iterator with the real libpcapng API
   in your project.
--------------------------------------------------------------------*/

#define CAML_NAME_SPACE               // avoid name clashes
#include <caml/mlvalues.h>
#include <caml/memory.h>
#include <caml/alloc.h>
#include <caml/callback.h>
#include <caml/custom.h>
#include <caml/fail.h>

#include <cstddef>
#include <cstdint>
#include <cstring>
#include <memory>
#include <vector>
#include <string>
#include <iostream>   // only for debugging; remove in production

/* -----------------------------------------------------------------
   Mock‑up of the libpcapng API.
   Replace this with the real header(s) from libpcapng.
----------------------------------------------------------------- */
namespace pcapng {

struct Frame {
    uint64_t timestamp;               // nanoseconds since epoch
    std::vector<uint8_t> data;        // raw packet bytes
};

class Iterator {
public:
    explicit Iterator(const std::string& path) : pos_(0) {
        // In a real implementation you would open the file, parse the
        // Section Header Block, etc.  Here we just create a few dummy frames.
        (void)path; // unused
        for (int i = 0; i < 5; ++i) {
            Frame f;
            f.timestamp = 1'600'000'000'000'000ULL + i * 1'000'000ULL; // 1 ms apart
            f.data = std::vector<uint8_t>(i+10, static_cast<uint8_t>(i));
            frames_.push_back(std::move(f));
        }
    }

    // Return true and fill *out with the next frame, or false on EOF.
    bool next(Frame* out) {
        if (pos_ >= frames_.size()) return false;
        *out = frames_[pos_++];
        return true;
    }

private:
    std::vector<Frame> frames_;
    size_t pos_;
};

} // namespace pcapng
/* ----------------------------------------------------------------- */

/* -----------------------------------------------------------------
   OCaml custom block for the opened file (holds the C++ iterator).
----------------------------------------------------------------- */
struct caml_pcapng {
    std::unique_ptr<pcapng::Iterator> it;
};

static void caml_pcapng_finalize(value v) {
    caml_pcapng* wrapper = reinterpret_cast<caml_pcapng*>(Data_custom_val(v));
    // unique_ptr destructor frees the iterator automatically.
    delete wrapper;
}

/* Minimal custom ops – we only need a finalizer. */
static struct custom_operations caml_pcapng_ops = {
    "pcapng.custom",
    caml_pcapng_finalize,
    custom_compare_default,
    custom_hash_default,
    custom_serialize_default,
    custom_deserialize_default,
    custom_fixed_length_default
};

/* -----------------------------------------------------------------
   OCaml entry points
----------------------------------------------------------------- */

/* open_file : string -> pcapng */
extern "C" CAMLprim value caml_pcapng_open_file(value fname) {
    CAMLparam1(fname);
    CAMLlocal1(res);

    const char* path = String_val(fname);
    // Try to construct the iterator; on failure raise a Failure.
    std::unique_ptr<pcapng::Iterator> it;
    try {
        it = std::make_unique<pcapng::Iterator>(std::string(path));
    } catch (const std::exception& e) {
        caml_failwith(e.what());
    }

    // Allocate the custom block.
    res = caml_alloc_custom(&caml_pcapng_ops, sizeof(caml_pcapng*), 0, 1);
    caml_pcapng* wrapper = new caml_pcapng;
    wrapper->it = std::move(it);
    Data_custom_val(res) = reinterpret_cast<intnat>(wrapper);

    CAMLreturn(res);
}

/* close : pcapng -> unit */
extern "C" CAMLprim value caml_pcapng_close(value vpcap) {
    CAMLparam1(vpcap);
    // The custom block’s finalizer will free the iterator when the
    // OCaml value is collected.  For an explicit close we just clear
    // the pointer so that later use triggers a clear error.
    caml_pcapng* wrapper = reinterpret_cast<caml_pcapng*>(Data_custom_val(vpcap));
    wrapper->it.reset();   // destroy the iterator now
    CAMLreturn(Val_unit);
}

/* -----------------------------------------------------------------
   Helper: build an OCaml [frame] record from a native Frame.
   The record layout in OCaml is:
     { timestamp : int64; data : bytes }
   which is compiled to a block of size 2, tag 0.
----------------------------------------------------------------- */
static value make_ocaml_frame(const pcapng::Frame& src) {
    CAMLparam0();
    CAMLlocal3(ocaml_frame, ts_val, data_val);

    // 1️⃣ timestamp (int64)
    ts_val = caml_copy_int64(static_cast<int64_t>(src.timestamp));

    // 2️⃣ data (bytes)
    data_val = caml_alloc_string(src.data.size());
    if (!src.data.empty()) {
        memcpy(String_val(data_val), src.data.data(), src.data.size());
    }

    // 3️⃣ record {timestamp; data}
    ocaml_frame = caml_alloc(2, 0);          // tag 0 = record
    Store_field(ocaml_frame, 0, ts_val);
    Store_field(ocaml_frame, 1, data_val);

    CAMLreturn(ocaml_frame);
}

/* iter_frames : pcapng -> (frame -> unit) -> unit */
extern "C" CAMLprim value caml_pcapng_iter_frames(value vpcap, value vcb) {
    CAMLparam2(vpcap, vcb);
    CAMLlocal1(ocaml_frame);

    // Extract the iterator.
    caml_pcapng* wrapper = reinterpret_cast<caml_pcapng*>(Data_custom_val(vpcap));
    if (!wrapper->it) caml_failwith("pcapng: iterator already closed");

    pcapng::Frame native_frame;
    while (wrapper->it->next(&native_frame)) {
        // Build the OCaml frame record for this native frame.
        ocaml_frame = make_ocaml_frame(native_frame);
        // Call the user‑provided callback.  We use caml_callback_exn so
        // that an exception in user code aborts the iteration cleanly.
        value res = caml_callback_exn(vcb, ocaml_frame);
        if (Is_exception_result(res)) {
            // Propagate the exception upward – the iterator stops.
            caml_raise(res);
        }
        // The OCaml value `ocaml_frame` goes out of scope; its
        // underlying bytes are GC‑managed, so no manual free is needed.
    }

    CAMLreturn(Val_unit);
}

/* -----------------------------------------------------------------
   Register the primitives for the OCaml side.
----------------------------------------------------------------- */
static struct caml_named_value {
    const char* name;
    value (*fn)(value);
} caml_primitives[] = {
    {"pcapng_open_file",   caml_pcapng_open_file},
    {"pcapng_close",       caml_pcapng_close},
    {"pcapng_iter_frames", caml_pcapng_iter_frames},
    {nullptr, nullptr}
};

extern "C" void caml_register_primitives(void) {
    for (int i = 0; caml_primitives[i].name != nullptr; ++i) {
        caml_register_named_value(caml_primitives[i].name,
                                  caml_primitives[i].fn);
    }
}

/* The OCaml runtime automatically calls caml_register_primitives()
   when the shared library is loaded (via `-custom` or `-dll`). */
```

